+function convertWikiLinks(text: string, options: LinkStyleOptions): string {
+  return text.replace(/(!?)\\[\\[([^\\]\
|]+)(?:\\|([^\\]\
|]*))?\\]\\]/g, (match, embed: string, target: string, display: string | undefined) => {
+    const isImage = embed === '!';
+    if ((isImage ? options.imageStyle : options.linkStyle) !== 'markdown') {
+      return match;
+    }
+
+    if (isImage && (display === '300' || display === '300x200')) {
+      display = undefined;
+    }
+    const label = display === undefined || display === '' ? defaultDisplay(target) : display;
+    return `${isImage ? '!' : ''}[${label}](${target})`;
+  });
+}
+
+function convertMarkdownLinks(text: string, options: LinkStyleOptions): string {
+  let result = '';
+  let index = 0;
+  while (index < text.length) {
+    const parsed = parseMarkdownLink(text, index);
+    if (!parsed) {
+      result += text[index++];
+      continue;
+    }
+
+    const style = parsed.image ? options.imageStyle : options.linkStyle;
+    if (style !== 'wiki' || parsed.target.includes('://')) {
+      result += parsed.source;
+    } else {
+      const display = unescapeMarkdown(parsed.label);
+      const target = unescapeMarkdown(parsed.target);
+      const omitDisplay = display === target || display === defaultDisplay(target);
+      const alias = omitDisplay || (parsed.image && display === '') ? '' : `|${display}`;
+      result += `${parsed.image ? '!' : ''}[[${target}${alias}]]`;
+    }
+    index = parsed.end;
+  }
+  return result;
+}
+
+type ParsedMarkdownLink = {image: boolean, label: string, target: string, source: string, end: number};
+
+function parseMarkdownLink(text: string, start: number): ParsedMarkdownLink | null {
+  const image = text[start] === '!';
+  const labelStart = image ? start + 1 : start;
+  if (text[labelStart] !== '[' || (start > 0 && text[start - 1] === '\\\')) {
+    return null;
+  }
+
+  const labelEnd = findClosingBracket(text, labelStart);
+  if (labelEnd === -1 || text[labelEnd + 1] !== '(') {
+    return null;
+  }
+  const destinationEnd = findClosingParenthesis(text, labelEnd + 1);
+  if (destinationEnd === -1) {
+    return null;
+  }
+
+  const label = text.slice(labelStart + 1, labelEnd);
+  const destination = text.slice(labelEnd + 2, destinationEnd);
+  if (label.includes('\
') || destination.includes('\
')) {
+    return null;
+  }
+  const target = parseDestination(destination);
+  if (target === null) {
+    return null;
+  }
+  const end = destinationEnd + 1;
+  return {image, label, target, source: text.slice(start, end), end};
+}
+
+function findClosingBracket(text: string, start: number): number {
+  let depth = 0;
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === '[') {
+      depth++;
+    } else if (text[index] === ']' && --depth === 0) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function findClosingParenthesis(text: string, start: number): number {
+  let depth = 0;
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === '(') {
+      depth++;
+    } else if (text[index] === ')' && --depth === 0) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function parseDestination(destination: string): string | null {
+  const trimmed = destination.trim();
+  if (trimmed.startsWith('<')) {
+    const closing = findUnescapedCharacter(trimmed, '>', 1);
+    if (closing === -1 || trimmed.slice(closing + 1).trim() !== '') {
+      return null;
+    }
+    return trimmed.slice(1, closing);
+  }
+
+  let sawWhitespace = false;
+  for (let index = 0; index < trimmed.length; index++) {
+    if (trimmed[index] === '\\\') {
+      index++;
+    } else if (/\\s/.test(trimmed[index])) {
+      sawWhitespace = true;
+    } else if (sawWhitespace) {
+      return null;
+    }
+  }
+  return trimmed;
+}
+
+function findUnescapedCharacter(text: string, character: string, start: number): number {
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === character) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function unescapeMarkdown(text: string): string {
+  return text.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultDisplay(target: string): string {
+  const headingIndex = target.indexOf('#');
+  if (headingIndex === -1) {
+    return target;
+  }
+  const page = target.slice(0, headingIndex);
+  const heading = target.slice(headingIndex + 1);
+  return page === '' ? heading : `${page} > ${heading}`;
+}
